import React, { useState } from 'react';
import useLocalStorage from '../hooks/useLocalStorage';
import KaliIcon from '../components/icons/KaliIcon';
import SpinnerIcon from '../components/icons/SpinnerIcon';
import RefreshIcon from '../components/icons/RefreshIcon';
import XCircleIcon from '../components/icons/XCircleIcon';

const KaliPage: React.FC = () => {
    // Default to the standard noVNC port/path
    const [vncUrl, setVncUrl] = useLocalStorage<string>('kali-vnc-url', 'http://localhost:6080/vnc.html');
    const [isConnected, setIsConnected] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [iframeKey, setIframeKey] = useState(0);

    const handleConnect = (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        // Simulate a brief connection check delay
        setTimeout(() => {
            setIsConnected(true);
            setIsLoading(false);
        }, 800);
    };

    const handleDisconnect = () => {
        setIsConnected(false);
    };

    const handleRefresh = () => {
        setIframeKey(prev => prev + 1);
    };

    if (isConnected) {
        return (
            <div className="h-full w-full flex flex-col bg-black relative">
                <iframe 
                    key={iframeKey}
                    src={vncUrl} 
                    className="flex-1 w-full h-full border-none"
                    allow="clipboard-read; clipboard-write; fullscreen"
                    title="Kali Linux VNC"
                />

                {/* Floating Controls Overlay */}
                <div className="absolute top-0 left-0 right-0 p-2 flex justify-center opacity-0 hover:opacity-100 transition-opacity duration-300">
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700 rounded-full px-4 py-2 flex items-center gap-3 shadow-xl">
                        <span className="text-xs font-bold text-slate-300 uppercase tracking-wider flex items-center gap-2">
                            <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                            Live Session
                        </span>
                        <div className="w-px h-4 bg-slate-600"></div>
                        <button 
                            onClick={handleRefresh}
                            className="p-1.5 rounded-full hover:bg-slate-700 text-slate-300 transition-colors"
                            title="Reload Screen"
                        >
                            <RefreshIcon className="w-4 h-4" />
                        </button>
                        <button 
                            onClick={handleDisconnect}
                            className="px-3 py-1 bg-red-600/80 hover:bg-red-600 text-white text-xs font-bold rounded-full transition-colors flex items-center gap-1"
                        >
                            <XCircleIcon className="w-3.5 h-3.5" /> Disconnect
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="h-full w-full bg-slate-900 flex flex-col items-center justify-center p-6 text-white overflow-y-auto">
            <div className="max-w-md w-full bg-slate-800/50 backdrop-blur-lg border border-slate-700 rounded-2xl p-8 shadow-2xl">
                <div className="flex flex-col items-center mb-8">
                    <div className="w-20 h-20 bg-slate-950 rounded-full flex items-center justify-center mb-4 shadow-inner border border-slate-800">
                        <KaliIcon className="w-12 h-12 text-white" />
                    </div>
                    <h1 className="text-2xl font-bold">Kali Linux Remote</h1>
                    <p className="text-slate-400 text-sm mt-2 text-center">
                        Connect to your local VirtualBox VM via noVNC.
                    </p>
                </div>

                <form onSubmit={handleConnect} className="space-y-6">
                    <div>
                        <label htmlFor="vnc-url" className="block text-xs font-bold uppercase text-slate-500 mb-2">VNC Server URL</label>
                        <input 
                            id="vnc-url"
                            type="url" 
                            value={vncUrl}
                            onChange={(e) => setVncUrl(e.target.value)}
                            className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-mono text-sm"
                            placeholder="http://localhost:6080/vnc.html"
                            required
                        />
                        <p className="text-[10px] text-slate-500 mt-2">
                            Ensure <code>websockify</code> is running on your host/guest machine.
                        </p>
                    </div>

                    <button 
                        type="submit" 
                        disabled={isLoading}
                        className="w-full py-3 px-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-lg shadow-lg shadow-indigo-900/20 transition-all flex items-center justify-center gap-2"
                    >
                        {isLoading ? <SpinnerIcon className="w-5 h-5 animate-spin" /> : 'Connect to Desktop'}
                    </button>
                </form>

                <div className="mt-8 pt-6 border-t border-slate-700/50">
                    <h3 className="text-xs font-bold text-slate-400 uppercase mb-3">Quick Setup Guide</h3>
                    <ol className="text-xs text-slate-500 space-y-2 list-decimal list-inside">
                        <li>Install <code>x11vnc</code> inside your Kali VM.</li>
                        <li>Install <code>novnc</code> and <code>websockify</code>.</li>
                        <li>Run: <code>websockify -D --web=/usr/share/novnc/ 6080 localhost:5900</code></li>
                        <li>Enter <code>http://localhost:6080/vnc.html</code> above.</li>
                    </ol>
                </div>
            </div>
        </div>
    );
};

export default KaliPage;

