                {/* Floating Controls Overlay */}
                <div className="absolute top-0 left-0 right-0 p-2 flex justify-center opacity-0 hover:opacity-100 transition-opacity duration-300">
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700 rounded-full px-4 py-2 flex items-center gap-3 shadow-xl">
