import { getChatMessages, addChatMessage, updateChatMessage, deleteChatMessage, clearChatMessages, getSupabase, isUsingMockData } from '../services/database';

interface DashboardPageProps {
  user: User;
  allUsers: User[];
  writeups: Post[];
  blogPosts: Post[];
  setAllUsers: (users: User[] | ((currentUsers: User[]) => User[])) => void;
  onLogout: () => void;
  onSendFriendRequest: (fromUser: User, toUserEmail: string) => void;
  onAcceptFriendRequest: (requestor: { email: string; name: string; }) => void;
  onRejectFriendRequest: (requestor: { email: string; name: string; }) => void;
  onRemoveFriend: (friendToRemove: { email: string; name: string; }) => void;
  onProfileUpdate: (updatedData: Partial<User>, silent?: boolean) => Promise<void>;
  onSavePost: (post: Post | Omit<Post, 'id' | 'created_at' | 'author' | 'comments' | 'liked_by'>) => Promise<Post | null>;
  onDeletePost: (postId: string, type: 'writeup' | 'blog') => Promise<void>;
  onLikePost: (post: Post, user: User) => Promise<void>;
  onAddCommentToPost: (post: Post, commentText: string) => Promise<void>;
  onDeleteCommentFromPost: (post: Post, commentId: string) => Promise<void>;
  onRequestWriteupAccess: () => void;
  onApproveWriteupAccess: (requestor: { email: string; name: string; }) => Promise<void>;
  onRejectWriteupAccess: (requestor: { email: string; name: string; }) => Promise<void>;
  onDeleteAccount: () => Promise<string | void>;
  onVerifyPassword: (password: string) => Promise<boolean>;
  onEmailChange: (newEmail: string) => Promise<string | void>;
  isSyncingProfile: boolean;
}

const APP_DEFINITIONS: AppDefinition[] = [
  { id: 'home', name: 'Home', icon: <HomeIcon />, component: HomePage, bgColorClass: 'bg-blue-500', accentColor: '#3b82f6' },
  { id: 'writeup', name: 'Writeups', icon: <WriteupIcon />, component: WriteupPage, bgColorClass: 'bg-indigo-500', accentColor: '#6366f1' },
  { id: 'blog', name: 'Blog', icon: <BlogIcon />, component: BlogPage, bgColorClass: 'bg-cyan-500', accentColor: '#06b6d4' },
  { id: 'chat', name: 'Chat', icon: <ChatIcon />, component: ChatPage, bgColorClass: 'bg-emerald-500', accentColor: '#10b981' },
  { id: 'notes', name: 'Notes', icon: <NotesIcon />, component: NotesPage, bgColorClass: 'bg-yellow-500', accentColor: '#f59e0b' },
  { id: 'todolist', name: 'To-Do', icon: <TodolistIcon />, component: TodolistPage, bgColorClass: 'bg-teal-500', accentColor: '#14b8a6' },
  { id: 'mywork', name: 'Portfolio', icon: <BriefcaseIcon />, component: MyWorkPage, bgColorClass: 'bg-violet-500', accentColor: '#8b5cf6' },
  { id: 'resources', name: 'Resources', icon: <ResourcesIcon />, component: ResourcesPage, bgColorClass: 'bg-orange-500', accentColor: '#f97316' },
  { id: 'live', name: 'Live', icon: <LiveIcon />, component: LivePage, bgColorClass: 'bg-rose-500', accentColor: '#f43f5e' },
  { id: 'kali', name: 'Kali Linux', icon: <KaliIcon />, component: KaliPage, bgColorClass: 'bg-slate-800', accentColor: '#1e293b' },
  { id: 'youtube', name: 'YouTube', icon: <YouTubeIcon />, component: YouTubePage, bgColorClass: 'bg-red-600', accentColor: '#dc2626' },
  { id: 'settings', name: 'Settings', icon: <SettingsIcon />, component: SettingsPage, bgColorClass: 'bg-slate-500', accentColor: '#64748b' },
  { id: 'search', name: 'Search', icon: <SearchIcon />, component: SearchPage, bgColorClass: 'bg-fuchsia-500', accentColor: '#d946ef' },
];

const ADMIN_APP: AppDefinition = { id: 'admin', name: 'Admin', icon: <AdminIcon />, component: AdminDashboardPage, bgColorClass: 'bg-amber-500', accentColor: '#f59e0b' };

const DashboardPage: React.FC<DashboardPageProps> = ({
  user, allUsers, writeups, blogPosts, setAllUsers, onLogout,
  onSendFriendRequest, onAcceptFriendRequest, onRejectFriendRequest, onRemoveFriend,
  onProfileUpdate, onSavePost, onDeletePost, onLikePost, onAddCommentToPost, onDeleteCommentFromPost,
  onRequestWriteupAccess, onApproveWriteupAccess, onRejectWriteupAccess,
  onDeleteAccount, onVerifyPassword, onEmailChange, isSyncingProfile
}) => {
    const { themeStyle } = useTheme();
    const { notifications } = useNotificationState();
    const [windows, setWindows] = useState<WindowInstance[]>([]);
    const [activeWindowId, setActiveWindowId] = useState<string | null>(null);
    const [startMenuOpen, setStartMenuOpen] = useState(false);
    const [taskbarPosition, setTaskbarPosition] = useLocalStorage<TaskbarPosition>('taskbarPosition', 'bottom');
    const [desktopIconSize, setDesktopIconSize] = useLocalStorage<DesktopIconSize>('desktopIconSize', 'medium');
    const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
    const [desktopIcons, setDesktopIcons] = useState<Record<string, { x: number; y: number }>>({});
    const [widgetState, setWidgetState] = useState<WidgetState>({ x: 20, y: 20, width: 300, height: 150 });
    const [sleepMode, setSleepMode] = useState(false);
    const [selectedIconId, setSelectedIconId] = useState<string | null>(null);
    const [isNotifPanelOpen, setIsNotifPanelOpen] = useState(false);

    const boundsRef = useRef<HTMLDivElement>(null);
    const startButtonRef = useRef<HTMLButtonElement>(null);

    const availableApps = user.role === 'admin' ? [...APP_DEFINITIONS, ADMIN_APP] : APP_DEFINITIONS;
    const unreadNotificationCount = notifications.filter(n => !n.isRead).length;

    // --- Load Preferences ---
    useEffect(() => {
        if (user.desktop_preferences) {
            if (user.desktop_preferences.iconPositions) setDesktopIcons(user.desktop_preferences.iconPositions);
            if (user.desktop_preferences.widgetState) setWidgetState(user.desktop_preferences.widgetState);
        }
    }, [user.id]); // Only run on user ID change to avoid loops

    // --- Save Preferences Debounced ---
    useEffect(() => {
        const timeoutId = setTimeout(() => {
            if (Object.keys(desktopIcons).length > 0) {
                onProfileUpdate({
                    desktop_preferences: {
                        ...user.desktop_preferences,
                        iconPositions: desktopIcons,
                        widgetState: widgetState
                    }
                }, true);
            }
        }, 2000);
        return () => clearTimeout(timeoutId);
    }, [desktopIcons, widgetState]);

    // --- Chat Logic ---
    useEffect(() => {
        const fetchMessages = async () => {
            const msgs = await getChatMessages();
            setChatMessages(msgs);
        };
        fetchMessages();

        const supabase = getSupabase();
        if (supabase && !isUsingMockData()) {
            const channel = supabase.channel('public:chat_messages')
                .on('postgres_changes', { event: '*', schema: 'public', table: 'chat_messages' }, payload => {
                    if (payload.eventType === 'INSERT') {
                        const newMsg = payload.new as any;
                        const author = allUsers.find(u => u.id === newMsg.author_id);
                        if (author) {
                            setChatMessages(prev => [...prev, { ...newMsg, author } as ChatMessage]);
                        }
                    }
                    if (payload.eventType === 'UPDATE') {
                        setChatMessages(prev => prev.map(m => m.id === payload.new.id ? { ...m, ...payload.new } : m));
                    }
                    if (payload.eventType === 'DELETE') {
                        setChatMessages(prev => prev.filter(m => m.id !== payload.old.id));
                    }
                })
                .subscribe();
            return () => { supabase.removeChannel(channel); };
        }
    }, [allUsers]);

    const handleSendMessage = async (text: string, replyToMessage?: ChatMessage) => {
        const tempId = crypto.randomUUID();
        const newMessage: ChatMessage = {
            id: tempId,
            author: user,
            text,
            timestamp: new Date().toISOString(),
            status: 'sending',
            reply_to: replyToMessage ? { id: replyToMessage.id, authorName: replyToMessage.author.name, text: replyToMessage.text } : undefined,
        };
        setChatMessages(prev => [...prev, newMessage]);

        try {
            const savedMsg = await addChatMessage({
                author: user,
                text,
                reply_to: newMessage.reply_to
            });
            if (savedMsg) {
                setChatMessages(prev => prev.map(m => m.id === tempId ? savedMsg : m));
            } else {
                throw new Error("Failed to save");
            }
        } catch (e) {
            setChatMessages(prev => prev.map(m => m.id === tempId ? { ...m, status: 'failed' } : m));
        }
    };

    const handleEditMessage = async (messageId: string, newText: string) => {
        setChatMessages(prev => prev.map(m => m.id === messageId ? { ...m, text: newText, edited_timestamp: new Date().toISOString() } : m));
        await updateChatMessage(messageId, { text: newText, edited_timestamp: new Date().toISOString() });
    };

    const handleDeleteMessage = async (messageId: string) => {
        setChatMessages(prev => prev.filter(m => m.id !== messageId));
        await deleteChatMessage(messageId);
    };

    const handleChatReaction = async (messageId: string, emoji: string) => {
        const msg = chatMessages.find(m => m.id === messageId);
        if (!msg) return;

        const currentReactions = msg.reactions || {};
        const userEmails = currentReactions[emoji] || [];

        let newReactions = { ...currentReactions };
        if (userEmails.includes(user.email)) {
            newReactions[emoji] = userEmails.filter(e => e !== user.email);
            if (newReactions[emoji].length === 0) delete newReactions[emoji];
        } else {
            newReactions[emoji] = [...userEmails, user.email];
        }

        setChatMessages(prev => prev.map(m => m.id === messageId ? { ...m, reactions: newReactions } : m));
        await updateChatMessage(messageId, { reactions: newReactions });
    };

    const handleClearChat = async () => {
        setChatMessages([]);
        await clearChatMessages();
    };

    // --- Window Management ---

    const openApp = useCallback((appId: string, props: Record<string, any> = {}, initialBounds?: DOMRect) => {
        const app = availableApps.find(a => a.id === appId);
        if (!app) {
            if (appId.startsWith('writeup/') || appId.startsWith('blog/')) {
                // Deep linking handling for posts
                const [type, id] = appId.split('/');
                const targetAppId = type === 'writeup' ? 'writeup' : 'blog';
                // Recursive call to open the correct app with deep link prop
                openApp(targetAppId, { deepLinkInfo: id });
                return;
            }
            // Handle hash based app opening (e.g. search/query)
            if (appId.startsWith('search/')) {
                const query = decodeURIComponent(appId.split('/')[1]);
                openApp('search', { query });
                return;
            }
            if (appId.startsWith('settings/')) {
                const section = appId.split('/')[1];
                openApp('settings', { deepLinkInfo: section });
                return;
            }
            if (appId.startsWith('admin/')) {
                const view = appId.split('/')[1];
                openApp('admin', { deepLinkInfo: view });
                return;
            }
            return; 
        }

        // Check for existing window
        const existingWindow = windows.find(w => w.appId === appId);
        if (existingWindow) {
            if (Object.keys(props).length > 0) {
                // Update props if new ones provided (e.g. deep linking)
                setWindows(prev => prev.map(w => w.id === existingWindow.id ? { ...w, props: { ...w.props, ...props }, refreshKey: w.refreshKey + 1, isMinimized: false } : w));
            } else {
                if (existingWindow.isMinimized) {
                    setWindows(prev => prev.map(w => w.id === existingWindow.id ? { ...w, isMinimized: false } : w));
                }
            }
            setActiveWindowId(existingWindow.id);
            return;
        }

        // Create new window
        const id = crypto.randomUUID();
        const defaultWidth = Math.min(1000, window.innerWidth * 0.9);
        const defaultHeight = Math.min(700, window.innerHeight * 0.8);

        // Calculate centered position or use icon launch position
        let x, y, w, h;

        if (initialBounds) {
            // Launch animation start (not fully implemented visually but logical prep)
            x = initialBounds.left;
            y = initialBounds.top;
            w = 0; // Will animate to default
            h = 0;
        } 

        // Center on screen
        const bounds = boundsRef.current?.getBoundingClientRect();
        if (bounds) {
            x = (bounds.width - defaultWidth) / 2 + (windows.length * 20);
            y = (bounds.height - defaultHeight) / 2 + (windows.length * 20);
        } else {
            x = 50; y = 50;
        }

        const newWindow: WindowInstance = {
            id,
            appId,
            title: app.name,
            icon: app.icon,
            x,
            y,
            width: defaultWidth,
            height: defaultHeight,
            zIndex: windows.length + 1,
            isMinimized: false,
            isMaximized: false,
            props,
            refreshKey: 0
        };

        setWindows(prev => [...prev, newWindow]);
        setActiveWindowId(id);
        setStartMenuOpen(false);
        setIsNotifPanelOpen(false); // Close notification panel when opening app
    }, [availableApps, windows]);

    const closeWindow = useCallback((id: string) => {
        setWindows(prev => prev.map(w => w.id === id ? { ...w, isClosing: true } : w));
        setTimeout(() => {
            setWindows(prev => prev.filter(w => w.id !== id));
            if (activeWindowId === id) {
                setActiveWindowId(null);
            }
        }, 300); // Wait for close animation
    }, [activeWindowId]);

    const minimizeWindow = useCallback((id: string) => {
        setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: true } : w));
        if (activeWindowId === id) setActiveWindowId(null);
    }, [activeWindowId]);

    const maximizeWindow = useCallback((id: string) => {
        setWindows(prev => prev.map(w => {
            if (w.id !== id) return w;
            const willMaximize = !w.isMaximized;
            return {
                ...w,
                isMaximized: willMaximize,
                preMaximizedState: willMaximize ? { x: w.x, y: w.y, width: w.width, height: w.height } : undefined,
                x: willMaximize ? 0 : w.preMaximizedState?.x || w.x,
                y: willMaximize ? 0 : w.preMaximizedState?.y || w.y,
                width: willMaximize ? (boundsRef.current?.clientWidth || window.innerWidth) : w.preMaximizedState?.width || w.width,
                height: willMaximize ? (boundsRef.current?.clientHeight || window.innerHeight) : w.preMaximizedState?.height || w.height,
            };
        }));
        setActiveWindowId(id);
    }, []);

    const focusWindow = useCallback((id: string) => {
        setActiveWindowId(id);
        setWindows(prev => {
            const win = prev.find(w => w.id === id);
            if (!win) return prev;
            const others = prev.filter(w => w.id !== id).map(w => ({ ...w, zIndex: w.zIndex > win.zIndex ? w.zIndex - 1 : w.zIndex }));
            return [...others, { ...win, zIndex: prev.length, isMinimized: false }].sort((a, b) => a.zIndex - b.zIndex);
        });
    }, []);

    const updateWindowBounds = useCallback((id: string, bounds: { x: number, y: number, width: number, height: number }) => {
        setWindows(prev => prev.map(w => w.id === id ? { ...w, ...bounds } : w));
    }, []);

    const refreshWindow = useCallback((id: string) => {
        setWindows(prev => prev.map(w => w.id === id ? { ...w, refreshKey: w.refreshKey + 1 } : w));
    }, []);

    const handleIconMove = useCallback((appId: string, pos: { x: number; y: number }) => {
        setDesktopIcons(prev => ({ ...prev, [appId]: pos }));
    }, []);

    const handleNavigateWithinApp = useCallback((path: string) => {
        // Parse path: "appId/subPath" or just "appId"
        const parts = path.split('/');
        const appId = parts[0];
        // If the path implies opening/switching context within an app:
        openApp(appId, { deepLinkInfo: parts.slice(1).join('/') || undefined });
    }, [openApp]);

    // Handle Hash Navigation (Deep Linking) on Mount & Change
    useEffect(() => {
        const handleHashChange = () => {
            const hash = window.location.hash.replace(/^#\/?/, '');
            if (hash && hash !== 'home') {
                const [appId, ...rest] = hash.split('/');
                const deepLinkInfo = rest.join('/');
                openApp(appId, deepLinkInfo ? { deepLinkInfo } : {});
            }
        };

        handleHashChange(); // Check on mount
        window.addEventListener('hashchange', handleHashChange);
        return () => window.removeEventListener('hashchange', handleHashChange);
    }, [openApp]);

    const handleToggleSleep = () => setSleepMode(!sleepMode);

    const handleDesktopClick = (e: React.MouseEvent) => {
        if (e.target === e.currentTarget) {
            setSelectedIconId(null);
            setStartMenuOpen(false);
            setIsNotifPanelOpen(false);
        }
    };

    const handleToggleNotificationPanel = (e: React.MouseEvent<HTMLButtonElement>) => {
        e.stopPropagation();
        setIsNotifPanelOpen(prev => !prev);
        setStartMenuOpen(false);
    };

    const isAnyWindowMaximized = windows.some(w => w.isMaximized && !w.isMinimized);

    return (
        <div className="h-full w-full overflow-hidden relative select-none" ref={boundsRef} onClick={handleDesktopClick}>
            {sleepMode && <SleepScreen onWake={handleToggleSleep} />}

            {/* Desktop Layer */}
            <div className="absolute inset-0 z-0">
                <DesktopWidgets 
                    state={widgetState} 
                    onStateChange={setWidgetState} 
                    boundsRef={boundsRef} 
                />

                {availableApps.map((app, index) => {
                    // Default positions if not set
                    const initialX = 20;
                    const initialY = 20 + (index * 100);
                    const pos = desktopIcons[app.id] || { x: initialX, y: initialY };

                    return (
                        <DesktopIcon 
                            key={app.id} 
                            app={app} 
                            x={pos.x} 
                            y={pos.y} 
                            onOpen={openApp} 
                            onPositionChange={handleIconMove}
                            boundsRef={boundsRef}
                            isSelected={selectedIconId === app.id}
                            onSelect={setSelectedIconId}
                            size={desktopIconSize}
                        />
                    );
                })}

                <div className="absolute bottom-20 right-6">
                    <SleepModeSwitch isWorkMode={!sleepMode} onToggle={handleToggleSleep} scale={0.4} />
                </div>
            </div>

            {/* Window Layer */}
            {windows.map(win => {
                const AppComp = availableApps.find(a => a.id === win.appId)?.component;
                if (!AppComp) return null;

                // Prop injection for specific apps
                let props: any = { ...win.props, onNavigateWithinApp: handleNavigateWithinApp };

                if (win.appId === 'home') props = { ...props, user, writeups, isPending: user.status === 'pending', onOpenApp: openApp };
                if (win.appId === 'writeup') props = { 
                    ...props, 
                    user, 
                    posts: writeups, 
                    onSavePost: (p: any) => onSavePost({...p, type: 'writeup'}), 
                    onDeletePost, 
                    onLikePost, 
                    onAddCommentToPost, 
                    onDeleteCommentFromPost,
                    onRequestAccess: onRequestWriteupAccess
                };
                if (win.appId === 'blog') props = {
                    ...props,
                    user,
                    posts: blogPosts,
                    onSavePost: (p: any) => onSavePost({...p, type: 'blog'}),
                    onDeletePost,
                    onLikePost,
                    onAddCommentToPost,
                    onDeleteCommentFromPost
                };
                if (win.appId === 'chat') props = {
                    ...props,
                    user,
                    allUsers,
                    messages: chatMessages,
                    onSendMessage: handleSendMessage,
                    onEditMessage: handleEditMessage,
                    onDeleteMessage: handleDeleteMessage,
                    onReaction: handleChatReaction,
                    onClearChat: handleClearChat,
                    onOpenApp: openApp
                };
                if (win.appId === 'settings') props = {
                    ...props,
                    user,
                    allUsers,
                    setAllUsers,
                    taskbarPosition,
                    setTaskbarPosition,
                    desktopIconSize,
                    setDesktopIconSize,
                    onAcceptFriendRequest,
                    onRejectFriendRequest,
                    onRemoveFriend,
                    onSendFriendRequest,
                    onLogout,
                    onProfileUpdate,
                    onDeleteAccount,
                    onVerifyPassword,
                    onEmailChange,
                    onOpenApp: openApp
                };
                if (win.appId === 'search') props = {
                    ...props,
                    user,
                    allApps: availableApps,
                    allPosts: [...writeups, ...blogPosts],
                    onOpenApp: openApp,
                    onClose: () => closeWindow(win.id)
                };
                if (win.appId === 'admin') props = {
                    ...props,
                    user,
                    allUsers,
                    setAllUsers,
                    onApproveWriteupAccess,
                    onRejectWriteupAccess,
                    liveUsers: [] // Placeholder
                };
                if (win.appId === 'notes') props = { ...props, user };
                if (win.appId === 'todolist') props = { ...props, user };
                if (win.appId === 'resources') props = { ...props, user };
                if (win.appId === 'mywork') props = { ...props, user, allUsers, writeups, blogPosts };
                if (win.appId === 'kali') props = { ...props, user, onProfileUpdate };
                if (win.appId === 'live') props = { ...props, onClose: () => closeWindow(win.id) };

                return (
                    <Window
                        key={win.id}
                        {...win}
                        accentColor={availableApps.find(a => a.id === win.appId)?.accentColor}
                        isActive={activeWindowId === win.id}
                        onClose={closeWindow}
                        onMinimize={minimizeWindow}
                        onMaximize={maximizeWindow}
                        onFocus={focusWindow}
                        onBoundsChange={updateWindowBounds}
                        onRefresh={refreshWindow}
                        boundsRef={boundsRef}
                    >
                        <AppComp {...props} />
                    </Window>
                );
            })}

            {/* Notification Panel */}
            {isNotifPanelOpen && (
                <div 
                    className="absolute z-[9998] w-80 md:w-96 max-h-[80vh] bg-white/90 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200 dark:border-slate-700 shadow-2xl rounded-2xl overflow-hidden animate-slide-up"
                    style={{
                        bottom: taskbarPosition === 'bottom' ? '70px' : '10px',
                        top: taskbarPosition === 'top' ? '60px' : 'auto',
                        right: taskbarPosition === 'right' ? '70px' : '10px',
                        left: taskbarPosition === 'left' ? '70px' : 'auto',
                        margin: taskbarPosition === 'bottom' || taskbarPosition === 'top' ? '0 10px' : '10px 0'
                    }}
                    onClick={(e) => e.stopPropagation()}
                >
                    <NotificationCenterPage onNavigateWithinApp={handleNavigateWithinApp} />
                </div>
            )}

            {/* Taskbar */}
            <Taskbar 
                position={taskbarPosition}
                apps={availableApps}
                openWindows={windows}
                activeWindowId={activeWindowId}
                onAppClick={openApp}
                onStartClick={() => {
                    setStartMenuOpen(!startMenuOpen);
                    setIsNotifPanelOpen(false);
                }}
                isStartMenuOpen={startMenuOpen}
                startButtonRef={startButtonRef}
                user={user}
                onLogout={onLogout}
                onOpenSettings={() => openApp('settings')}
                isAnyWindowMaximized={isAnyWindowMaximized && themeStyle === 'mac'}
                allAppsForSearch={availableApps}
                searchablePosts={[...writeups, ...blogPosts]}
                onSearch={(q) => openApp('search', { query: q })}
                unreadNotificationCount={unreadNotificationCount}
                onOpenNotifications={handleToggleNotificationPanel}
            />

            <InstallPWAButton />
        </div>
    );
};

export default DashboardPage;

